@@ -2700,10 +2708,38 @@ func printStorageClass(obj *storage.StorageClass, options printers.GenerateOptio
 	return []metav1.TableRow{row}, nil
 }

+// newestDefaultStorageClassName returns the name of the newest default StorageClass
+// when multiple defaults exist, or empty string if there are zero or one defaults.
+func newestDefaultStorageClassName(list *storage.StorageClassList) string {
+	defaults := 0
+	var newestDefault *storage.StorageClass
+	for i := range list.Items {
+		if storageutil.IsDefaultAnnotation(list.Items[i].ObjectMeta) {
+			defaults++
+			if newestDefault == nil || list.Items[i].CreationTimestamp.After(newestDefault.CreationTimestamp.Time) {
+				newestDefault = &list.Items[i]
+			}
+		}
+	}
+	if defaults > 1 && newestDefault != nil {
+		return newestDefault.Name
+	}
+	return ""
+}
+
 func printStorageClassList(list *storage.StorageClassList, options printers.GenerateOptions) ([]metav1.TableRow, error) {
 	rows := make([]metav1.TableRow, 0, len(list.Items))
+	effectiveDefault := newestDefaultStorageClassName(list)
 	for i := range list.Items {
-		r, err := printStorageClass(&list.Items[i], options)
+		var label string
+		if effectiveDefault != "" && storageutil.IsDefaultAnnotation(list.Items[i].ObjectMeta) {
+			if list.Items[i].Name == effectiveDefault {
+				label = "(default, effective)"
+			} else {
+				label = "(default, inactive)"
+			}
+		}
+		r, err := printStorageClassInternal(&list.Items[i], options, label)
 		if err != nil {
 			return nil, err
 		}

diff --git a/pkg/printers/internalversion/printers.go b/pkg/printers/internalversion/printers.go
index 40bf85f9e45..c6218760ffa 100644
--- a/pkg/printers/internalversion/printers.go
+++ b/pkg/printers/internalversion/printers.go
@@ -2709,6 +2709,38 @@ func printStorageClassList(list *storage.StorageClassList, options printers.Gene
 		}
 		rows = append(rows, r...)
 	}
+
+	// When multiple StorageClasses are marked as default, indicate which one
+	// is the effective default (the newest one, with name as tiebreaker).
+	defaultClasses := []int{}
+	for i := range list.Items {
+		if storageutil.IsDefaultAnnotation(list.Items[i].ObjectMeta) {
+			defaultClasses = append(defaultClasses, i)
+		}
+	}
+	if len(defaultClasses) > 1 {
+		// Find the effective default: primary sort by creation timestamp (newest first),
+		// secondary sort by name (ascending).
+		effectiveIdx := defaultClasses[0]
+		for _, idx := range defaultClasses[1:] {
+			ei := list.Items[effectiveIdx]
+			ej := list.Items[idx]
+			if ej.CreationTimestamp.UnixNano() > ei.CreationTimestamp.UnixNano() ||
+				(ej.CreationTimestamp.UnixNano() == ei.CreationTimestamp.UnixNano() && ej.Name < ei.Name) {
+				effectiveIdx = idx
+			}
+		}
+		for _, idx := range defaultClasses {
+			name := rows[idx].Cells[0].(string)
+			if idx == effectiveIdx {
+				// Already has " (default)" suffix from printStorageClass; no change needed
+				continue
+			}
+			// Replace " (default)" with " (default, inactive)" for non-effective defaults
+			rows[idx].Cells[0] = strings.Replace(name, " (default)", " (default, inactive)", 1)
+		}
+	}
+
 	return rows, nil
 }

