+// Tests that HTTP filters are built and invoked for routes that use a cluster
+// specifier plugin.
+func (s) TestXDSResolverHTTPFilters_ClusterSpecifierPlugin(t *testing.T) {
+	// Register a custom httpFilter builder for the test and use a channel to
+	// get notified when the interceptor is invoked.
+	testFilterName := t.Name()
+	fb := &testHTTPFilterWithRPCMetadata{
+		logger:        t,
+		typeURL:       testFilterName,
+		newStreamChan: testutils.NewChannelWithSize(1),
+	}
+	httpfilter.Register(fb)
+	defer httpfilter.UnregisterForTesting(fb.typeURL)
+
+	ctx, cancel := context.WithTimeout(context.Background(), defaultTestTimeout)
+	defer cancel()
+	nodeID := uuid.New().String()
+	mgmtServer, _, _, bc := setupManagementServerForTest(t, nodeID)
+
+	listener := e2e.DefaultClientListener(defaultTestServiceName, defaultTestRouteConfigName)
+	hcm := &v3httppb.HttpConnectionManager{}
+	if err := listener.GetApiListener().GetApiListener().UnmarshalTo(hcm); err != nil {
+		t.Fatalf("Failed to unmarshal listener HCM: %v", err)
+	}
+	hcm.HttpFilters = []*v3httppb.HttpFilter{
+		newHTTPFilter(t, "foo-failing", testFilterName, "foo-failing", "filter interceptor error"),
+		e2e.RouterHTTPFilter,
+	}
+	hcmAny := testutils.MarshalAny(t, hcm)
+	listener.ApiListener.ApiListener = hcmAny
+	listener.FilterChains[0].Filters[0].ConfigType = &v3listenerpb.Filter_TypedConfig{
+		TypedConfig: hcmAny,
+	}
+
+	routes := []*v3routepb.RouteConfiguration{e2e.RouteConfigResourceWithOptions(e2e.RouteConfigOptions{
+		RouteConfigName:              defaultTestRouteConfigName,
+		ListenerName:                 defaultTestServiceName,
+		ClusterSpecifierType:         e2e.RouteConfigClusterSpecifierTypeClusterSpecifierPlugin,
+		ClusterSpecifierPluginName:   "cspA",
+		ClusterSpecifierPluginConfig: testutils.MarshalAny(t, &wrapperspb.StringValue{Value: "anything"}),
+	})}
+	configureResources(ctx, t, mgmtServer, nodeID, []*v3listenerpb.Listener{listener}, routes, nil, nil)
+
+	stateCh, _, _ := buildResolverForTarget(t, resolver.Target{URL: *testutils.MustParseURL("xds:///" + defaultTestServiceName)}, bc)
+	cs := verifyUpdateFromResolver(ctx, t, stateCh, "")
+
+	res, err := cs.SelectConfig(iresolver.RPCInfo{Context: ctx, Method: "/service/method"})
+	if err != nil {
+		t.Fatalf("cs.SelectConfig(): %v", err)
+	}
+	if res.Interceptor == nil {
+		t.Fatal("cs.SelectConfig() returned nil interceptor for cluster specifier plugin route")
+	}
+
+	_, err = res.Interceptor.NewStream(ctx, iresolver.RPCInfo{Context: ctx, Method: "/service/method"}, func() {}, func(context.Context, func()) (iresolver.ClientStream, error) {
+		return nil, status.Error(codes.Internal, "unexpected call to delegated stream creation")
+	})
+	if got, want := status.Code(err), codes.Unavailable; got != want {
+		t.Fatalf("res.Interceptor.NewStream() error code, got: %v, want: %v", got, want)
+	}
+	if got, want := err.Error(), "filter interceptor error"; !strings.Contains(got, want) {
+		t.Fatalf("Unexpected NewStream() error, got: %v, want to contain: %q", err, want)
+	}
+
+	val, err := fb.newStreamChan.Receive(ctx)
+	if err != nil {
+		t.Fatalf("Timeout waiting for filter to be invoked: %v", err)
+	}
+	gotCfg := val.(overallFilterConfig)
+	wantCfg := overallFilterConfig{BasePath: "foo-failing", Error: "filter interceptor error"}
+	if diff := cmp.Diff(wantCfg, gotCfg); diff != "" {
+		t.Fatalf("Unexpected filter config (-want +got):\n%s", diff)
+	}
+
+	res.OnCommitted()
+}
+
