 				newObj.GetObjectKind().GroupVersionKind(), "namespace", ns, "name", name)
 		})
-		// Explicitly remove managedFields on failure, so that
-		// we can't have garbage in it.
+		// Preserve the existing managedFields on failure to avoid data loss.
+		if liveAccessor, liveErr := meta.Accessor(liveObj); liveErr == nil {
+			if newAccessor, newErr := meta.Accessor(newObj); newErr == nil {
