diff --git a/pkg/scheduler/framework/plugins/dynamicresources/dynamicresources.go b/pkg/scheduler/framework/plugins/dynamicresources/dynamicresources.go
index 46db7e45c09..e317cea5ecd 100644
--- a/pkg/scheduler/framework/plugins/dynamicresources/dynamicresources.go
+++ b/pkg/scheduler/framework/plugins/dynamicresources/dynamicresources.go
@@ -238,7 +238,7 @@ func (pl *DynamicResources) EventsToRegister(_ context.Context) ([]fwk.ClusterEv
 		// Adding the ResourceClaim name to the pod status makes pods waiting for their ResourceClaim schedulable.
 		{Event: fwk.ClusterEvent{Resource: fwk.Pod, ActionType: fwk.UpdatePodGeneratedResourceClaim}, QueueingHintFn: pl.isSchedulableAfterPodChange},
 		// A pod might be waiting for a class to get created or modified.
-		{Event: fwk.ClusterEvent{Resource: fwk.DeviceClass, ActionType: fwk.Add | fwk.Update}},
+		{Event: fwk.ClusterEvent{Resource: fwk.DeviceClass, ActionType: fwk.Add | fwk.Update}, QueueingHintFn: pl.isSchedulableAfterDeviceClassChange},
 		// Adding or updating a ResourceSlice might make a pod schedulable because new resources became available.
 		{Event: fwk.ClusterEvent{Resource: fwk.ResourceSlice, ActionType: fwk.Add | fwk.Update}},
 	}
@@ -352,6 +352,61 @@ func (pl *DynamicResources) isSchedulableAfterPodChange(logger klog.Logger, pod
 	return fwk.Queue, nil
 }

+// isSchedulableAfterDeviceClassChange is invoked for add and update device class
+// events. It checks whether the changed class is referenced by one of the pod's
+// claims because only then can the event affect scheduling.
+func (pl *DynamicResources) isSchedulableAfterDeviceClassChange(logger klog.Logger, pod *v1.Pod, oldObj, newObj interface{}) (fwk.QueueingHint, error) {
+	originalClass, modifiedClass, err := schedutil.As[*resourceapi.DeviceClass](oldObj, newObj)
+	if err != nil {
+		// Shouldn't happen.
+		return fwk.Queue, fmt.Errorf("unexpected object in isSchedulableAfterDeviceClassChange: %w", err)
+	}
+	if modifiedClass == nil {
+		return fwk.QueueSkip, nil
+	}
+
+	usesClass := false
+	if err := pl.foreachPodResourceClaim(pod, func(_ string, claim *resourceapi.ResourceClaim) {
+		if resourceClaimUsesDeviceClass(claim, modifiedClass.Name) {
+			usesClass = true
+		}
+	}); err != nil {
+		// This is not an unexpected error: we know that
+		// foreachPodResourceClaim only returns errors for "not
+		// schedulable".
+		logger.V(6).Info("pod is not schedulable after device class change", "pod", klog.KObj(pod), "deviceclass", klog.KObj(modifiedClass), "reason", err.Error())
+		return fwk.QueueSkip, nil
+	}
+	if !usesClass {
+		logger.V(6).Info("unrelated device class got modified", "pod", klog.KObj(pod), "deviceclass", klog.KObj(modifiedClass))
+		return fwk.QueueSkip, nil
+	}
+	if originalClass != nil && apiequality.Semantic.DeepEqual(&originalClass.Spec, &modifiedClass.Spec) {
+		logger.V(6).Info("device class got modified where the pod doesn't care", "pod", klog.KObj(pod), "deviceclass", klog.KObj(modifiedClass))
+		return fwk.QueueSkip, nil
+	}
+
+	logger.V(5).Info("device class used by pod got created or updated", "pod", klog.KObj(pod), "deviceclass", klog.KObj(modifiedClass))
+	return fwk.Queue, nil
+}
+
+func resourceClaimUsesDeviceClass(claim *resourceapi.ResourceClaim, className string) bool {
+	for _, request := range claim.Spec.Devices.Requests {
+		if len(request.FirstAvailable) == 0 {
+			if request.Exactly.DeviceClassName == className {
+				return true
+			}
+			continue
+		}
+		for _, subRequest := range request.FirstAvailable {
+			if subRequest.DeviceClassName == className {
+				return true
+			}
+		}
+	}
+	return false
+}
+
 // podResourceClaims returns the ResourceClaims for all pod.Spec.PodResourceClaims.
 func (pl *DynamicResources) podResourceClaims(pod *v1.Pod) ([]*resourceapi.ResourceClaim, error) {
 	claims := make([]*resourceapi.ResourceClaim, 0, len(pod.Spec.ResourceClaims))

