@@ -213,6 +213,34 @@ func getRPCInfo(ctx context.Context) *rpcInfo {
 	return ri
 }

+// serverRPCInfoKey is a separate context key for server-side rpcInfo, to
+// prevent a server handler that makes outgoing client calls using the incoming
+// server context from overwriting the server's rpcInfo with client rpcInfo.
+type serverRPCInfoKey struct{}
+
+func setServerRPCInfo(ctx context.Context, ri *rpcInfo) context.Context {
+	return context.WithValue(ctx, serverRPCInfoKey{}, ri)
+}
+
+// getServerRPCInfo returns the server-side rpcInfo stored in the context, or
+// nil if there isn't one.
+func getServerRPCInfo(ctx context.Context) *rpcInfo {
+	ri, _ := ctx.Value(serverRPCInfoKey{}).(*rpcInfo)
+	return ri
+}
+
+// getOrCreateServerRPCAttemptInfo retrieves or creates a server-scoped rpc
+// attemptInfo object and ensures it is set in the context along with the
+// rpcInfo using the server-specific context key.
+func getOrCreateServerRPCAttemptInfo(ctx context.Context) (context.Context, *attemptInfo) {
+	ri := getServerRPCInfo(ctx)
+	if ri != nil {
+		return ctx, ri.ai
+	}
+	ri = &rpcInfo{ai: &attemptInfo{}}
+	return setServerRPCInfo(ctx, ri), ri.ai
+}
+
 func removeLeadingSlash(mn string) string {
 	return strings.TrimLeft(mn, "/")
 }
