+			s.httpErr = &httpError{code: grpcErrorCode, msg: msg}
+			s.status = se
+			if atomic.CompareAndSwapUint32(&s.headerChanClosed, 0, 1) {
+				s.noHeaders = true
+				close(s.headerChan)
+			}
+			return
+		}
+
 		t.closeStream(s, se.Err(), true, http2.ErrCodeProtocol, se, nil, endStream)
 		return
 	}
